import { Link, useLocation, useNavigate } from "react-router-dom";
import { logoutUser } from "../services/auth";

export default function Sidebar() {
  const location = useLocation();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logoutUser();
    navigate("/login");
  };

  const navItems = [
    { name: "Dashboard", path: "/team-lead", icon: "📊" },
    { name: "Create User", path: "/create-user", icon: "👥" },
    { name: "Agent View", path: "/agent", icon: "👀" },
  ];

  return (
    <div className="fixed inset-y-0 left-0 w-[268px] bg-gradient-to-b from-[#111a3a] via-[#182653] to-[#0f766e] text-white shadow-xl flex flex-col overflow-y-auto z-10">
      <div className="p-6 mb-4">
        <h2 className="min-h-[82px] flex items-center justify-center text-center text-[1.05rem] font-extrabold tracking-tight border border-white/10 rounded-[22px] bg-white/10 backdrop-blur-md">
          Aamer CSR Portal
        </h2>
      </div>

      <nav className="flex-1 px-4 space-y-2">
        {navItems.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <Link
              key={item.name}
              to={item.path}
              className={`flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 ${
                isActive
                  ? "bg-white/20 text-white shadow-[inset_3px_0_0_#22d3ee]"
                  : "text-white/80 hover:bg-white/10 hover:text-white hover:translate-x-[2px]"
              }`}
            >
              <span className="text-[0.98rem] w-5 text-center text-white/70">{item.icon}</span>
              <span className="font-bold text-[0.91rem]">{item.name}</span>
            </Link>
          );
        })}
      </nav>

      <div className="p-4 mt-auto">
        <button
          onClick={handleLogout}
          className="w-full flex items-center gap-3 px-3 py-2.5 text-red-300 hover:bg-red-400/10 hover:text-red-200 rounded-xl transition-colors font-bold text-[0.91rem]"
        >
          <span className="w-5 text-center">🚪</span>
          Sign Out
        </button>
      </div>
    </div>
  );
}
